import React, { useState, useEffect } from 'react';
import logo from '../assets/LOGO.png';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import LoadingPage from './LoadingPage';
import { sendPasswordResetEmail } from 'firebase/auth';
import { auth } from '../firebase';

const LoginPage = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const { login, googleSignIn, loading, user } = useAuth();
    const navigate = useNavigate();
    const [error, setError] = useState('');
    const [showWelcome, setShowWelcome] = useState(false);

    // ── Forgot-password state ──────────────────────────────────────────────────
    const [forgotMode, setForgotMode] = useState(false);
    const [resetEmail, setResetEmail] = useState('');
    const [resetSending, setResetSending] = useState(false);
    const [resetMsg, setResetMsg] = useState(null); // { type, text }

    useEffect(() => {
        if (user) navigate('/');
    }, [user, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        try {
            await login({ email, password });
            setShowWelcome(true);
        } catch (err) {
            setError('Failed to sign in. Please check your credentials.');
            console.error(err);
        }
    };

    const handleGoogleSignIn = async () => {
        setError('');
        try {
            await googleSignIn();
            setShowWelcome(true);
        } catch (err) {
            setError('Failed to sign in with Google. Please try again.');
            console.error(err);
        }
    };

    const handleSendReset = async (e) => {
        e.preventDefault();
        if (!resetEmail.trim()) {
            setResetMsg({ type: 'error', text: 'Please enter your email address.' });
            return;
        }
        setResetSending(true);
        setResetMsg(null);
        try {
            await sendPasswordResetEmail(auth, resetEmail.trim());
            setResetMsg({ type: 'success', text: `Reset link sent to ${resetEmail.trim()}. Check your inbox.` });
        } catch (err) {
            const msg = err.code === 'auth/user-not-found'
                ? 'No account found with that email.'
                : err.code === 'auth/invalid-email'
                    ? 'Invalid email address.'
                    : 'Failed to send reset email. Try again.';
            setResetMsg({ type: 'error', text: msg });
        }
        setResetSending(false);
    };

    if (loading) return <LoadingPage />;

    if (showWelcome) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-gray-100 dark:bg-gray-900">
                <div className="text-center p-8 bg-white dark:bg-gray-800 rounded-lg shadow-xl">
                    <div className="mx-auto w-16 h-16 bg-green-500 rounded-full flex items-center justify-center mb-4">
                        <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                        </svg>
                    </div>
                    <h1 className="text-2xl font-bold text-gray-800 dark:text-white">Welcome Back!</h1>
                    <p className="text-gray-600 dark:text-gray-400">You've been successfully signed in.</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex flex-col bg-white dark:bg-gray-900">
            {/* Grid Background */}
            <div className="absolute top-0 left-0 w-full h-full bg-grid-pattern overflow-hidden pointer-events-none z-0" />

            <main className="relative flex-grow flex flex-col items-center justify-center z-10 p-4">
                <div className="w-full max-w-md bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm rounded-xl p-8 border border-gray-200/50 dark:border-gray-700/50 shadow-lg">

                    {/* Header */}
                    <div className="text-center mb-8">
                        <div className="mb-4">
                            <img src={logo} alt="AlgoCore Logo" className="w-24 h-24 mx-auto" />
                        </div>
                        <h1 className="text-3xl font-bold text-gray-800 dark:text-white">
                            {forgotMode ? 'Reset Password' : 'Welcome to AlgoCore'}
                        </h1>
                        <p className="text-gray-600 dark:text-gray-400 mt-2">
                            {forgotMode
                                ? "Enter your email and we'll send you a reset link."
                                : 'Sign in to access your dashboard.'}
                        </p>
                    </div>

                    {/* ── Forgot-password panel ── */}
                    {forgotMode ? (
                        <div className="space-y-4">
                            {resetMsg && (
                                <div className={`p-3 text-sm rounded-lg border ${resetMsg.type === 'success'
                                    ? 'text-green-700 bg-green-50 border-green-300 dark:bg-green-900/30 dark:text-green-400 dark:border-green-800'
                                    : 'text-red-700 bg-red-50 border-red-300 dark:bg-red-900/30 dark:text-red-400 dark:border-red-800'
                                    }`}>
                                    {resetMsg.text}
                                </div>
                            )}

                            <form onSubmit={handleSendReset} className="space-y-4">
                                <div>
                                    <label htmlFor="reset-email" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                                        Email Address
                                    </label>
                                    <input
                                        id="reset-email"
                                        type="email"
                                        value={resetEmail}
                                        onChange={e => setResetEmail(e.target.value)}
                                        autoFocus
                                        placeholder="your.email@example.com"
                                        className="w-full px-4 py-2 text-sm border border-gray-300 rounded-lg shadow-sm bg-gray-50 dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                                    />
                                </div>

                                <button
                                    type="submit"
                                    disabled={resetSending}
                                    className="w-full px-4 py-3 text-sm font-semibold text-white bg-blue-600 rounded-lg hover:bg-blue-700 disabled:bg-blue-400 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-all duration-300"
                                >
                                    {resetSending ? (
                                        <span className="flex items-center justify-center gap-2">
                                            <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z" />
                                            </svg>
                                            Sending…
                                        </span>
                                    ) : 'Send Reset Link'}
                                </button>
                            </form>

                            <button
                                onClick={() => { setForgotMode(false); setResetMsg(null); setResetEmail(''); }}
                                className="w-full text-sm text-gray-500 hover:text-blue-600 dark:hover:text-blue-400 transition text-center mt-1"
                            >
                                ← Back to Sign In
                            </button>
                        </div>
                    ) : (
                        /* ── Normal sign-in panel ── */
                        <>
                            {error && (
                                <div className="p-3 mb-4 text-sm text-red-700 bg-red-100 border border-red-300 rounded-lg dark:bg-red-900/30 dark:text-red-400 dark:border-red-800">
                                    {error}
                                </div>
                            )}

                            <form onSubmit={handleSubmit} className="space-y-6">
                                <div className="space-y-4">
                                    <div>
                                        <label htmlFor="email" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                                            Email Address
                                        </label>
                                        <input
                                            id="email"
                                            type="email"
                                            value={email}
                                            onChange={e => setEmail(e.target.value)}
                                            required
                                            className="w-full px-4 py-2 text-sm border border-gray-300 rounded-lg shadow-sm bg-gray-50 dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                                            placeholder="your.email@university.edu"
                                        />
                                    </div>

                                    <div>
                                        <div className="flex items-center justify-between mb-1">
                                            <label htmlFor="password" className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                                                Password
                                            </label>
                                            <button
                                                type="button"
                                                onClick={() => { setForgotMode(true); setResetEmail(email); setError(''); }}
                                                className="text-xs text-blue-600 hover:text-blue-700 dark:text-blue-400 dark:hover:text-blue-300 font-medium transition"
                                            >
                                                Forgot password?
                                            </button>
                                        </div>
                                        <input
                                            id="password"
                                            type="password"
                                            value={password}
                                            onChange={e => setPassword(e.target.value)}
                                            required
                                            className="w-full px-4 py-2 text-sm border border-gray-300 rounded-lg shadow-sm bg-gray-50 dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                                            placeholder="••••••••"
                                        />
                                    </div>
                                </div>

                                <button
                                    type="submit"
                                    className="w-full px-4 py-3 text-sm font-semibold text-white bg-blue-600 rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-all duration-300 transform hover:scale-105"
                                >
                                    Sign In
                                </button>
                            </form>

                            <div className="relative my-6">
                                <div className="absolute inset-0 flex items-center">
                                    <div className="w-full border-t border-gray-300 dark:border-gray-600" />
                                </div>
                                <div className="relative flex justify-center text-xs">
                                    <span className="px-2 bg-white dark:bg-gray-800 text-gray-500 dark:text-gray-400">OR</span>
                                </div>
                            </div>

                            <button
                                onClick={handleGoogleSignIn}
                                className="flex items-center justify-center w-full px-4 py-3 space-x-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg shadow-sm hover:bg-gray-50 dark:bg-gray-700 dark:border-gray-600 dark:text-white dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-all"
                            >
                                <svg className="w-5 h-5" viewBox="0 0 24 24">
                                    <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                                    <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                                    <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                                    <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                                </svg>
                                <span>Continue with Google</span>
                            </button>
                        </>
                    )}
                </div>
            </main>
        </div>
    );
};

export default LoginPage;